export async function handleSkillUsage(ctx: Context): Promise<void> {
  const { isAllowed, formatRelative } = deps();
  if (!isAllowed(ctx)) return;
  const skillDir = detectSkillDir();
  if (skillDir.startsWith("(")) {
    await ctx.reply(`📚 Skills overview\n\n⚠️ SKILL_DIR 未設定：${skillDir}`);
    return;
  }

  let sweep: { added: string[]; newlyOrphaned: string[]; deOrphaned: string[] };
  try {
    sweep = await usageStore.migrateFromDisk(skillDir);
  } catch (err) {
    await ctx.reply(
      `📚 Skills overview\n\n⚠️ 讀取 ${skillDir} 失敗：${(err as Error).message}`,
    );
    return;
  }

  const all = await usageStore.listAll(skillDir);
  const entries = Object.entries(all.skills).map(([name, e]) => ({ name, ...e }));
  const total = entries.length;
  if (total === 0) {
    await ctx.reply(
      `📚 Skills overview — 0 skills at ${skillDir}\n\n(目錄裡沒有任何 SKILL.md 檔)`,
    );
    return;
  }

  const pinned = entries.filter((e) => e.pinned);
  const orphaned = entries.filter((e) => e.orphan);
  const neverUsed = entries.filter((e) => e.use_count === 0 && !e.orphan);
  const recentlyAdded = [...entries]
    .filter((e) => !e.orphan)
    .sort((a, b) => b.created_at.localeCompare(a.created_at))
    .slice(0, 5);
  const topUsed = [...entries]
    .filter((e) => e.use_count > 0)
    .sort((a, b) => b.use_count - a.use_count)
    .slice(0, 5);

    .slice(0, 5);

  const lines: string[] = [];
  lines.push(`📚 Skills overview — ${total} skills at ${skillDir}`);
  lines.push("");
  if (sweep.added.length > 0) {
    lines.push(`➕ 新增追蹤：${sweep.added.join(", ")}`);
  }
  if (sweep.newlyOrphaned.length > 0) {
    lines.push(`⚠️ 新發現 orphan（SKILL.md 不見了）：${sweep.newlyOrphaned.join(", ")}`);
  }
  if (sweep.deOrphaned.length > 0) {
    lines.push(`♻️ 重現：${sweep.deOrphaned.join(", ")}`);
  }
  if (sweep.added.length + sweep.newlyOrphaned.length + sweep.deOrphaned.length > 0) {
    lines.push("");
  }

  if (pinned.length > 0) {
    lines.push(`📌 Pinned (${pinned.length}):`);
    for (const e of pinned) {
      const tag = e.notes ? ` — ${e.notes}` : "";
      lines.push(`  • ${e.name}${tag}`);
    }
    lines.push("");
  }

  if (topUsed.length > 0) {
    lines.push(`🔥 最常用 (${topUsed.length}):`);
    for (const e of topUsed) {
      const reasonTail = e.last_reason
        ? ` — ${e.last_reason.length > 40 ? e.last_reason.slice(0, 40) + "…" : e.last_reason}`
        : "";
      lines.push(`  • ${e.name}  (${e.use_count}×)${reasonTail}`);
    }
    lines.push("");
  }

  if (recentlyAdded.length > 0) {
    lines.push(`🆕 最近新增 (top 5):`);
    for (const e of recentlyAdded) {
      const d = new Date(e.created_at);
      const ago = formatRelative(d.getTime() - Date.now());
      lines.push(`  • ${e.name}  (${ago})`);
    }
    lines.push("");
  }

  if (neverUsed.length > 0) {
    lines.push(`💤 Bridge 端從未看到 agent 用過 (${neverUsed.length}):`);
    const names = neverUsed.map((e) => e.name).slice(0, 10);
    lines.push(`  ${names.join(", ")}${neverUsed.length > 10 ? ` …+${neverUsed.length - 10}` : ""}`);
    lines.push("");
  }

  if (orphaned.length > 0) {
    lines.push(`👻 Orphan entries (skill-usage.json 有但磁碟沒 SKILL.md) (${orphaned.length}):`);
    lines.push(`  ${orphaned.map((e) => e.name).join(", ")}`);
    lines.push("");
  }

  lines.push(
    "ℹ️ Note: bridge 端統計只在 agent 回覆帶 <<SKILL_USED>> token 時計數。" +
      "「從未看到使用」可能代表該 skill 真的沒用、或 agent 忘記加 token。",
  );

  for (const e of entries) {
    await usageStore.markListed(skillDir, e.name).catch(() => {});
  }

  const body = lines.join("\n");
  if (body.length > TG_MAX) {
    await ctx.reply(body.slice(0, TG_MAX - 20) + "\n… (trimmed)");
  } else {
    await ctx.reply(body);
  }
}

