export async function renderGoalStatus(ctx: Context, chatId: number): Promise<void> {
  const { formatRelative } = deps();
  const s = await goalStore.get(config.memoryDir, chatId);
  if (!s) {
    await ctx.reply(
      "🎯 Goal: (none)\n\n" +
        "用 /goal <objective> 設一個會持續到達成的標的。例如：\n" +
        "  /goal 把 tmp/scratch.txt 寫入四行，每行寫一個 word",
    );
    return;
  }
  const statusEmoji: Record<string, string> = {
    active: "🏃",
    paused: "⏸",
    done: "✓",
    cleared: "🗑",
  };
  const lines = [
    `${statusEmoji[s.status] ?? "🎯"} Goal status: **${s.status}**`,
    `Objective: ${s.objective}`,
    `Turns: ${s.turns_used}/${s.max_turns}`,
  ];
  if (s.last_reason) lines.push(`Last reason: ${s.last_reason}`);
  if (s.last_turn_at) {
    const ago = formatRelative(Date.parse(s.last_turn_at) - Date.now());
    lines.push(`Last turn: ${ago} ago`);
  }
  lines.push("");
  if (s.status === "active") {
    lines.push("/goal pause — 暫停 continuation loop");
    lines.push("/goal clear — 放棄 goal");
  } else if (s.status === "paused") {
    lines.push("/goal resume — 續跑（turns_used 歸零）");
    lines.push("/goal clear — 放棄 goal");
  } else {
    lines.push("/goal <new text> — 設新 objective");
  }
  await ctx.reply(lines.join("\n"));
}
